import { MarkerInteractionState } from '../../../types/marker.js';

const MARKER_DEFAULT_BRIGHTNESS_PERCENTAGE = '100%';
const mapStateBrightnessPercentage: Record<
  'dark' | 'light',
  Record<MarkerInteractionState, string>
> = {
  dark: {
    default: MARKER_DEFAULT_BRIGHTNESS_PERCENTAGE,
    hovered: '110%',
    active: '120%',
    inactive: '60%',
  },
  light: {
    default: MARKER_DEFAULT_BRIGHTNESS_PERCENTAGE,
    hovered: '90%',
    active: '80%',
    inactive: '140%',
  },
};
/**
 * Gets the proper brightness for canvas filter depending on the theme and the state of the marker
 *
 * @param theme -
 * @param state -
 */
export const getMarkerBrightnessPercentageBasedOnState = (
  theme: 'dark' | 'light',
  state: MarkerInteractionState,
) => mapStateBrightnessPercentage[theme][state];
